var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 비밀 서고에는 수많은 <color=#ffd34c>기적</color>이 잠들어 있다.","JPN":"聖皇庁の秘密書庫には数多くの<color=#ffd34c>奇跡</color>が眠っている。","ENG":"Countless <color=#ffd34c>Miracles</color> lie dormant in the Holy Curia's secret library.","TWN":"聖皇廳秘密書庫中沉睡著無數<color=#ffd34c>奇蹟</color>。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"관리국의 존재가 수면 위로 드러나기 전부터 교회가 수집해 온 기적의 실마리들.","JPN":"管理局の存在が明らかになる前から、教会が収集してきた奇跡の手がかり。","ENG":"They are clues that the church had been collecting long before the existence of the Administration was revealed to the public.","TWN":"在管理局的存在浮出水面之前，教會就已經收集了奇蹟的線索。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 소리 내어 읽은 것만으로도 배탈을 치료할 수 있다고 전해지는 마도서부터.","JPN":"たとえるなら、声に出して読んだだけでも腹痛を治癒することができると言われている魔導書から。","ENG":"For instance, there is a grimoire that can cure stomachaches just by reading its passages out loud.","TWN":"比如說，只要大聲朗讀就能治癒腹痛的魔法書。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 누명을 쓰고 새하얀 피를 흘리며 숨을 거둔 순교자의 유언장까지.","JPN":"濡れ衣を着せられて白色の血を流しながら息絶えた殉教者の遺言書まで。","ENG":"Or even the will of a martyr who died after being falsely accused and shedding pure white blood.","TWN":"再比如，背負冤屈，流著純白的血，臨終前的殉教者遺言。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 설립 이래로, 시성성은 수단과 방법을 가리지 않고 기적의 행방을 쫓아왔으며.","JPN":"聖皇庁の設立以来、列聖省は手段を択ばずに奇跡の行方を追跡し。","ENG":"Since the establishment of the Holy Curia, the Dicastery for the Causes of Saints has pursued the whereabouts of Miracles by any means possible.","TWN":"自聖皇廳成立以來，封聖部一直不擇手段地追尋奇蹟的蹤跡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"또한 그 기적에 경중은 없으니…….","JPN":"また、その奇跡に軽重はない……","ENG":"Moreover, no Miracle is weighed greater or lesser than another...","TWN":"而且那奇蹟沒有輕重之分……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"따라서 비밀 서고의 사서는 있는 그대로의 기적, 그 자체를 보존할 의무가 있다.","JPN":"よって、秘密書庫の司書はありのままの奇跡、それ自体を保存する義務がある。","ENG":"Therefore, the librarian of the secret library has a duty to preserve the Miracle itself.","TWN":"因此，秘密書庫的管理員有義務將這些奇蹟原原本本地保存下來。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 아무리 사소하고 보잘것없어 보일지라도.","JPN":"時にその奇跡がとても小さく些細なものに見えたとしても。","ENG":"At times, they may seem insignificant.","TWN":"有時候，那些奇蹟看起來微不足道。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 세상에서 완전히 지워버리고 싶을 정도로 낯부끄러운 것일지라도.","JPN":"時にその奇跡がこの世から完全に消しさりたいほど不名誉なことであるとしても。","ENG":"At other times, they are embarrassing to the point one wishes to completely erase the Miracles from the world.","TWN":"有時候，那些奇蹟甚至會讓人羞愧到想要將其徹底從世界上抹去。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"주께서 사서에게 부여하신 의무는 기적의 보존이지, 결코 말소가 아닐 터.","JPN":"主が司書に与えられし義務は奇跡の保存であり、決して抹消ではない。","ENG":"Nevertheless, the duty given to the librarian by the Lord is to preserve, not destroy.","TWN":"但主賦予管理員的職責是保存奇蹟，絕不是抹除。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에…….","JPN":"そのため……","ENG":"And so...","TWN":"正因為如此……"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"subtitle","speaker":null,"text":{"KOREA":"성황청 시성성, 기적 심사 보고서\\n성무 코드 <color=#ffd34c>X12MAS25</color>","JPN":"聖皇庁の列聖省、奇跡審査報告書\\n聖務コード<color=#ffd34c>X12MAS25</color>","ENG":"[[","TWN":"聖皇廳封聖部, 奇蹟審查報告書\\n聖務代碼 <color=#ffd34c>X12MAS25</color>","SCN":"圣廷圣化部, 奇迹审查报告书\\n圣务代码 <color=#ffd34c>X12MAS25</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"subtitle","speaker":null,"text":{"KOREA":"X12MAS25는 집행사제 클로디아 넬슨이 성탄절을 축하하기 위해 제조한 케이크가 생명력을 획득.\\n현장에 있던 다수의 인원을 공격한 사건이다.","JPN":"X12MAS25は執行司祭クラウディア・ネルソンが聖誕祭を祝うために製造したケーキに\\n生命が宿り、現場にいた多数の人員を攻撃した事件である。","ENG":"[[","TWN":"X12MAS25是治理祭司克勞迪婭·尼爾森為慶祝聖誕節而製作的蛋糕獲得生命力量，\\n並攻擊現場的多數人員的事件。","SCN":"X12MAS25是执行祭司克劳迪娅·尼尔森为了庆祝圣诞节而制作的蛋糕获得了生命力量，\\n并攻击了现场的多数人员的事件。","DEU":"[[","FRA":"[["},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"subtitle","speaker":null,"text":{"KOREA":"시성성 조사관이 현장을 조사한 결과,\\n케이크의 잔여물에서 이면세계의 성분들이 검출되었으나, 잔여 침식파는 검출되지 않아 인체에는 무해했다.","JPN":"列聖省の調査官が現場を調査した結果、\\nケーキの残骸から裏世界の成分が検出されたが、\\n残余侵食波は検出されず人体には無害であった。","ENG":"[[","TWN":"封聖部監察官對現場進行調查結果，\\n在蛋糕的殘留物中檢測到異界成分，但未檢測到殘留的侵蝕波，因此對人體是無害的。","SCN":"圣化监察官对现场进行了调查，结果显示，蛋糕的残留物中检测到了异界成分，但未检测到残留的侵蚀波，因此对人体是无害的。","DEU":"[[","FRA":"[["},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"subtitle","speaker":null,"text":{"KOREA":"또한 생명력을 획득한 케이크는 자아를 가지고 있었으며, 높은 지성을 보유하고 있었다는 진술을 확보할 수 있었다.","JPN":"また、生命が宿ったケーキは自我を持ち、\\n高い知性を保有していたという証言を確保した。","ENG":"Additionally, testimonies confirmed that the cake was sentient and displayed a high level of intelligence.","TWN":"此外，獲得生命力量的蛋糕不僅擁有自我意識，還被證實具有高度的智慧。","SCN":"此外，获得了生命力量的蛋糕不仅拥有自我意识，还被证实具有高度的智慧。","DEU":"Additionally, testimonies confirmed that the cake was sentient and displayed a high level of intelligence.","FRA":"Additionally, testimonies confirmed that the cake was sentient and displayed a high level of intelligence."},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"subtitle","speaker":null,"text":{"KOREA":"위와 같은 사실에 근거.\\n조사관은 클로디아 넬슨이 제조한 케이크는 일반적인 침식현상과는 관련이 없다고 결론지었다.","JPN":"上記の事実に基づき。\\n調査官はクラウディア・ネルソンが製造したケーキは\\n一般的な侵食現象とは関係がないと結論づけた。","ENG":"[[","TWN":"根據上述事實，\\n監察官得出結論，克勞迪婭·尼爾森製作的蛋糕與一般的侵蝕現象無關。","SCN":"根据上述事实，\\n监察官得出结论，克劳迪娅·尼尔森制作的蛋糕与一般的侵蚀现象无关。","DEU":"[[","FRA":"[["},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"이에 따라, 시성성은 이 사건을 초자연적 기적현상에 대한 단서로 판단.\\n케이크를 통하여 다른 차원의 존재를 불러내어 직접 소통할 수 있다는 가능성을 제시하였다.","JPN":"これにより、\\n列聖省はこの事件を超自然的な奇跡現象についての手がかりと判断。\\nケーキを媒介に他の次元の存在を呼び出し直接疎通できるという可能性を提示した。","ENG":"[[","TWN":"因此，封聖部委員會認為這一事件是超自然奇蹟現象的線索。\\n透過蛋糕，透露出與另一個維度的存在進行直接溝通的可能性。","SCN":"因此，圣化委员会认为这一事件是超自然奇迹现象的线索。\\n通过蛋糕，展示了与另一个维度的存在进行直接沟通的可能性。","DEU":"[[","FRA":"[["},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"subtitle","speaker":null,"text":{"KOREA":"보다 면밀한 조사를 위해, 제9호 기적심의회의 협조를 요구하는 바.\\n집행사제 비블리데 루체에게 X12MAS25에 대한 상세한 경위서와 해당 케이크 레시피의 제출을 요한다.","JPN":"より詳しい調査のため、第9号奇跡審議会の協力を要求する。\\n執行司祭ビブリデ・ルーチェにはX12MAS25についての詳細経緯書と、\\n該当のケーキレシピの提出を要する。","ENG":"[[","TWN":"為進行更詳細的調查，需要第九奇蹟議會的協助。\\n要求治理祭司布莉黛·露契提交關於X12MAS25的詳細經過報告以及相關蛋糕的食譜。","SCN":"为了进行更细致的调查，需要第九奇迹议会的协助。\\n要求执行祭司比布莉黛·露契提交关于X12MAS25的详细经过报告以及相关蛋糕的食谱。","DEU":"[[","FRA":"[["},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 어린 양이 고해성사의 기도를 올립니다.","JPN":"子羊が告解の祈りを捧げます。","ENG":"I offer a prayer of confession.","TWN":"你的小羊正在懺悔祈禱。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에 여기 한 젊은 사서가 고민에 빠졌다.","JPN":"そのためここに、1人の若い司書が悩んでいる。","ENG":"One young librarian finds herself in deep contemplation.","TWN":"因此，這裡有一位年輕的圖書管理員陷入了困境。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 손에 넣은 것은 어느 디저트의 <color=#ffd34c>레시피</color>.","JPN":"彼女が手に入れたのは、あるデザートの<color=#ffd34c>レシピ</color>。","ENG":"She has in her hands a certain dessert <color=#ffd34c>recipe</color>.","TWN":"她得到的是某種甜點的<color=#ffd34c>食譜</color>。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 어쩌면 기적을 향한 실마리가 될지도 모르는 것.","JPN":"それはもしかしたら、奇跡への手がかりとなり得るかもしれないもの。","ENG":"Perhaps this, too, could be a clue to a Miracle.","TWN":"那或許是通往奇蹟的線索。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 저를 시험에 들게 하십니까…….","JPN":"私を試さないでください……","ENG":"Why do You lead me into temptation...?","TWN":"為什麼要考驗我……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어, 어째서…….","JPN":"ど、どうして……","ENG":"J-just why...?","TWN":"為，為什麼……"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};